import{_ as a,o as i,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"F03: 合約負債與營收能見度 - FA 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8064_東捷/20260429/F03_合約負債與營收能見度_財務分析專家.md","filePath":"審計報告庫/財務審計/8064_東捷/20260429/F03_合約負債與營收能見度_財務分析專家.md"}'),o={name:"審計報告庫/財務審計/8064_東捷/20260429/F03_合約負債與營收能見度_財務分析專家.md"};function e(n,t,s,d,_,c){return i(),r("div",null,[...t[0]||(t[0]=[l('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f03-合約負債與營收能見度-fa-審計報告" tabindex="-1">F03: 合約負債與營收能見度 - FA 審計報告 <a class="header-anchor" href="#f03-合約負債與營收能見度-fa-審計報告" aria-label="Permalink to &quot;F03: 合約負債與營收能見度 - FA 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>合約負債與未來收入的變動關係為何？訂單轉化為實質營收的速度是否出現停滯？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：合約負債3年連降至7.98億，能見101天，營收動能風險高。</li><li><strong>風險評級</strong>：高 — 4年新低，能見度3.4月</li><li><strong>數據時效</strong>：2025/12年報+2026/Q1營收</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>： <ul><li>合約負債（流動）：1,641M→1,107M→<strong>798M</strong>（2022→2025，累計-51.4%）</li><li>合約負債/營收比：42.5%→<strong>27.8%</strong>（2025年-14.7pp）</li><li>能見天數：155天→<strong>101天</strong></li><li>營收YoY：-23.7%→-12.9%→<strong>+10.2%</strong>（2025反彈）</li><li>2026 Q1累計6.73億(YoY+29.95%)，動能延續</li></ul></li><li><strong>診斷見解</strong>：合約負債在營收反彈年加速萎縮，典型「吃老本」：新單獲取未跟上去化速度，安全邊際大幅收窄。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-訂單領先指標-leading-indicator" tabindex="-1">1. 訂單領先指標（Leading Indicator） <a class="header-anchor" href="#_1-訂單領先指標-leading-indicator" aria-label="Permalink to &quot;1. 訂單領先指標（Leading Indicator）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：合約負債2022-2025連年下滑，16.41億→7.98億(-51.4%)，2025年(-27.9%)為4年最大降幅。營收+10.2%但合約負債加速萎縮，反映2025年營收來自舊訂單去化而非新單轉化。</li></ul><h3 id="_2-含金量分析-order-quality" tabindex="-1">2. 含金量分析（Order Quality） <a class="header-anchor" href="#_2-含金量分析-order-quality" aria-label="Permalink to &quot;2. 含金量分析（Order Quality）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：全為流動合約負債(一年內)，客戶以面板+半導體設備為主，半導體占比由個位數升至15-20%。合約負債萎縮發生在面板→半導體轉型期，舊單去化完畢、新單未補上，造成「換血空窗」，非退單潮。</li></ul><h3 id="_3-產業對位-industry-context" tabindex="-1">3. 產業對位（Industry Context） <a class="header-anchor" href="#_3-產業對位-industry-context" aria-label="Permalink to &quot;3. 產業對位（Industry Context）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：設備業合約負債/營收比30-50%，同業帆宣35-40%、均豪30-35%。東捷27.8%低於同業均值，101天能見度(約3.4月)偏短（健康水位4-6月）。若2026 Q2-Q3新單未補，下半年營收有斷崖風險。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析（Skepticism Mandate） <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析（Skepticism Mandate）&quot;">​</a></h2><ul><li><p><strong>空頭風險一：訂單池枯竭</strong>。合約負債/營收比從42%降至28%，4年最低。798M合約負債僅支撐101天營收(日均786.5萬)，若2026年營收持平，Q3末前無新單補入即有斷層。2026 Q1營收YoY+30%但合約負債尚未公告回升，動能可持續性存疑。</p></li><li><p><strong>空頭風險二：收入認列空間模糊</strong>。勤業眾信連續2年將收入認列列為關鍵查核事項，設備控制權可能於交機安裝前即認列。管理層可提前認列收入，同步減少合約負債、增加營收，雙向扭曲合約負債/營收比真實性。</p></li><li><p><strong>空頭風險三：轉型過渡訂單真空</strong>。面板→半導體轉型中，半導體設備認證期6-12個月，新訂單轉化慢。若2026年先進封裝資本支出調整，轉型進度恐受挫，能見度進一步惡化。</p></li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源（Veracity Check） <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源（Veracity Check）&quot;">​</a></h2><ul><li><strong>年報</strong>: OK — 2025/Q4、2024/Q4、2023/Q4 合併財報 <ul><li>2025/12/31 BS P.8: 合約負債-流動 <strong>798,045千元</strong>（佔負債15%）</li><li>2024/12/31 BS P.8: 合約負債-流動 <strong>1,107,241千元</strong>（佔負債19%）</li><li>2025年度營收淨額 <strong>2,870,684千元</strong>（P.9 綜合損益表）</li><li>2024年度營收淨額 <strong>2,603,886千元</strong></li><li>2023/12/31 BS P.8: 合約負債-流動 <strong>1,230,656千元</strong>（佔負債21%）</li><li>2022/12/31 BS P.8: 合約負債-流動 <strong>1,641,480千元</strong>（佔負債24%）</li></ul></li><li><strong>Web Search</strong>: OK <ul><li>2026年1月營收196,579千元、2月225,354千元、3月251,479千元，Q1累計673,412千元（YoY+29.95%）</li><li>公司展望：2025半導體設備占比15-20%，目標2026年超30%（法說會/新聞稿）</li><li>關鍵查核事項：勤業眾信將收入認列真實性列為KAM（2024-2025連續2年）</li></ul></li><li><strong>FinMind</strong>: 無法調用（環境無finmind模組），以年報原始數據替代</li><li><strong>核心核對碼</strong>: <code>8064_2025_BS_P8: CL=798045k | Rev=2,870,684k | CL/Rev=27.8%</code></li></ul>',19)])])}const u=a(o,[["render",e]]);export{g as __pageData,u as default};
